DROP TABLE IF EXISTS items;
CREATE TABLE IF NOT EXISTS items (
  id TEXT PRIMARY KEY,
  type TEXT NOT NULL,
  country TEXT NOT NULL,
  value TEXT NOT NULL,
  year TEXT NOT NULL,
  quality TEXT NOT NULL,
  serialNumber TEXT,
  title TEXT NOT NULL,
  description TEXT NOT NULL,
  thumbnailUrl TEXT NOT NULL,
  lowResUrl TEXT NOT NULL,
  highResUrl TEXT NOT NULL
);

